import React, { useState, useEffect } from 'react';
import { useNavigate, Navigate } from 'react-router-dom';
import { useAuth } from './hooks/useAuth';

/**
 * Home component for the expense tracker. This component handles
 * displaying the user's transactions, calculating totals and
 * providing a form to add new entries. All data is stored in
 * localStorage, so the app continues to work offline without
 * external dependencies. The design uses Tailwind CSS classes
 * to provide a modern and responsive user interface.
 */
export const Home = () => {
  const { userID, name, photo, isAuth } = useAuth();
  const navigate = useNavigate();

  // Load transactions from localStorage or initialize with an empty array
  const [transactions, setTransactions] = useState(() => {
    const transactionKey = `transactions_${userID}`;
    const stored = localStorage.getItem(transactionKey);
    if (stored) {
      try {
        return JSON.parse(stored);
      } catch (e) {
        console.error('Failed to parse transactions from localStorage', e);
      }
    }
    return [];
  });

  // Form fields for new entry
  const [newExp, setNewExp] = useState('');
  const [newPrice, setNewPrice] = useState('');
  const [newType, setNewType] = useState('Expense');
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Totals state: balance, income and expense
  const [total, setTotal] = useState({ balance: 0, income: 0, expense: 0 });

  // Recalculate totals whenever the transactions change
  useEffect(() => {
    let income = 0;
    let expense = 0;
    transactions.forEach((t) => {
      const amount = Number(t.price);
      if (t.type === 'Income') {
        income += amount;
      } else {
        expense += amount;
      }
    });
    setTotal({ balance: income - expense, income, expense });
  }, [transactions]);

  // Persist transactions to localStorage on every change
  useEffect(() => {
    const transactionKey = `transactions_${userID}`;
    localStorage.setItem(transactionKey, JSON.stringify(transactions));
  }, [transactions, userID]);

  // Add a new transaction to the list
  const handleAdd = () => {
    if (!newExp.trim() || !newPrice) return;
    setIsSubmitting(true);
    setTimeout(() => {
      const newEntry = {
        id: Date.now().toString(),
        userID,
        exp: newExp.trim(),
        price: Number(newPrice),
        type: newType,
        createdAt: new Date().toISOString(),
      };
      setTransactions((prev) => [...prev, newEntry]);
      setNewExp('');
      setNewPrice('');
      setNewType('Expense');
      setIsSubmitting(false);
    }, 300);
  };

  // Delete a transaction by its id
  const handleDelete = (id) => {
    setTransactions((prev) => prev.filter((t) => t.id !== id));
  };

  // Sign the user out by clearing auth info and navigating to login
  const handleSignOut = () => {
    localStorage.removeItem('auth');
    navigate('/');
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && newExp.trim() && newPrice) {
      handleAdd();
    }
  };

  // Guard route: redirect unauthenticated users to the login page
  if (!isAuth) {
    return <Navigate to="/" />;
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-950 via-blue-950 to-slate-950 relative overflow-hidden">
      {/* Background animations */}
      <div className="absolute inset-0 overflow-hidden pointer-events-none">
        <div className="absolute top-20 right-20 w-96 h-96 bg-blue-500/5 rounded-full blur-3xl"></div>
        <div className="absolute bottom-20 left-20 w-96 h-96 bg-amber-500/5 rounded-full blur-3xl"></div>
      </div>

      {/* Header */}
      <div className="relative z-10 bg-slate-900/50 backdrop-blur-xl border-b border-blue-500/20">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-5 flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-lg bg-gradient-to-br from-blue-500 to-amber-500 flex items-center justify-center text-xl shadow-lg">
              💰
            </div>
            <h1 className="text-2xl font-bold bg-gradient-to-r from-blue-300 to-amber-300 bg-clip-text text-transparent">Budget Buddy</h1>
          </div>
          <div className="flex items-center gap-6">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 rounded-full bg-gradient-to-br from-blue-400 to-blue-600 flex items-center justify-center text-white font-bold text-sm shadow-lg">
                {name.charAt(0).toUpperCase()}
              </div>
              <span className="text-sm font-semibold text-blue-100">{name}</span>
            </div>
            <button
              onClick={handleSignOut}
              className="px-4 py-2 text-sm font-semibold text-blue-200 hover:text-blue-100 hover:bg-blue-500/20 rounded-lg transition-all duration-200 border border-blue-500/30 hover:border-blue-500/60"
            >
              Sign Out
            </button>
          </div>
        </div>
      </div>

      {/* Main content */}
      <div className="relative z-10 max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
        {/* Overview and entry form */}
        <div className="bg-white p-6 rounded-lg shadow">
          <h2 className="text-xl font-semibold mb-4">Overview</h2>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
            <div className="bg-gray-50 p-4 rounded-lg text-center">
              <p className="text-sm text-gray-500">Balance</p>
              <p
                className={`text-2xl font-bold ${
                  total.balance >= 0 ? 'text-green-600' : 'text-red-600'
                }`}
              >
                ₹{Math.abs(total.balance).toLocaleString()}
              </p>
            </div>
            <div className="bg-gray-50 p-4 rounded-lg text-center">
              <p className="text-sm text-gray-500">Income</p>
              <p className="text-2xl font-bold text-green-600">
                ₹{total.income.toLocaleString()}
              </p>
            </div>
            <div className="bg-gray-50 p-4 rounded-lg text-center">
              <p className="text-sm text-gray-500">Expense</p>
              <p className="text-2xl font-bold text-red-600">
                ₹{total.expense.toLocaleString()}
              </p>
            </div>
          </div>

          <h3 className="text-lg font-semibold mt-6 mb-2">Add an Entry</h3>
          <input
            type="text"
            placeholder="Description"
            value={newExp}
            onChange={(e) => setNewExp(e.target.value)}
            className="w-full p-3 border border-gray-300 rounded mb-3 focus:outline-none focus:ring-2 focus:ring-blue-400"
          />
          <input
            type="number"
            placeholder="Amount"
            value={newPrice}
            onChange={(e) => setNewPrice(e.target.value)}
            className="w-full p-3 border border-gray-300 rounded mb-3 focus:outline-none focus:ring-2 focus:ring-blue-400"
          />
          <div className="flex items-center space-x-6 mb-4">
            <label className="flex items-center">
              <input
                type="radio"
                name="type"
                value="Expense"
                checked={newType === 'Expense'}
                onChange={(e) => setNewType(e.target.value)}
                className="mr-2"
              />
              Expense
            </label>
            <label className="flex items-center">
              <input
                type="radio"
                name="type"
                value="Income"
                checked={newType === 'Income'}
                onChange={(e) => setNewType(e.target.value)}
                className="mr-2"
              />
              Income
            </label>
          </div>
          <button
            onClick={handleAdd}
            className="bg-blue-500 hover:bg-blue-600 text-white px-4 py-2 rounded w-full sm:w-auto"
          >
            Add Entry
          </button>
        </div>

        {/* Transactions table */}
        <div className="bg-white p-6 rounded-lg shadow overflow-x-auto">
          <h2 className="text-xl font-semibold mb-4">Transactions</h2>
          {transactions.length === 0 ? (
            <p className="text-gray-500">No transactions yet.</p>
          ) : (
            <table className="min-w-full divide-y divide-gray-200">
              <thead className="bg-gray-50">
                <tr>
                  <th className="px-3 py-2 text-left text-sm font-medium text-gray-500 uppercase tracking-wider">
                    Description
                  </th>
                  <th className="px-3 py-2 text-left text-sm font-medium text-gray-500 uppercase tracking-wider">
                    Amount
                  </th>
                  <th className="px-3 py-2 text-left text-sm font-medium text-gray-500 uppercase tracking-wider">
                    Type
                  </th>
                  <th className="px-3 py-2"></th>
                </tr>
              </thead>
              <tbody className="bg-white divide-y divide-gray-200">
                {transactions.map((tran) => (
                  <tr key={tran.id} className="hover:bg-gray-50">
                    <td className="px-3 py-2 whitespace-nowrap">{tran.exp}</td>
                    <td className="px-3 py-2 whitespace-nowrap">
                      ₹{Number(tran.price).toLocaleString()}
                    </td>
                    <td
                      className={`px-3 py-2 whitespace-nowrap ${
                        tran.type === 'Expense' ? 'text-red-600' : 'text-green-600'
                      }`}
                    >
                      {tran.type}
                    </td>
                    <td className="px-3 py-2 whitespace-nowrap text-right">
                      <button
                        onClick={() => handleDelete(tran.id)}
                        className="bg-red-500 hover:bg-red-600 text-white px-3 py-1 rounded"
                      >
                        Delete
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      </div>
    </div>
  );
};
